import { BrowserRouter, Routes, Route, Link } from "react-router-dom";

// Наші "сторінки" - це просто звичайні компоненти!
function Home() {
  return <h2>🏠 Головна сторінка (Твій список бажанок міг би бути тут)</h2>;
}

function Profile() {
  return <h2>👤 Профіль користувача</h2>;
}

function Settings() {
  return <h2>⚙️ Налаштування системи</h2>;
}

export default function App() {
  return (
    // BrowserRouter - це "ядро" нашого роутера, яке стежить за адресним рядком
    <BrowserRouter>
      {/* Це наше навігаційне меню. Воно буде видно на ВСІХ сторінках */}
      <nav
        style={{
          padding: "20px",
          background: "#313244",
          display: "flex",
          gap: "15px",
        }}
      >
        {/* Link - це розумна заміна тегу <a>. Вона міняє URL БЕЗ перезавантаження сторінки */}
        <Link to="/" style={{ color: "#cdd6f4" }}>
          Головна
        </Link>
        <Link to="/profile" style={{ color: "#cdd6f4" }}>
          Профіль
        </Link>
        <Link to="/settings" style={{ color: "#cdd6f4" }}>
          Налаштування
        </Link>
      </nav>

      {/* А тут відбувається магія. 
          Routes перевіряє поточний URL і малює тільки ТОЙ компонент, який співпадає */}
      <div
        style={{
          padding: "30px",
          background: "#1e1e2e",
          color: "#cdd6f4",
          minHeight: "80vh",
        }}
      >
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/profile" element={<Profile />} />
          <Route path="/settings" element={<Settings />} />
        </Routes>
      </div>
    </BrowserRouter>
  );
}
